import argparse
import json
import pickle
from pathlib import Path
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic_utility_over_dist"}

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors:
        return None
    nodes = obs.get("nodes", [])
    if not nodes:
        return neighbors[0]

    def coord_to_tuple(c):
        if isinstance(c, np.ndarray):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        if isinstance(c, (list, tuple)):
            return (round(float(c[0]), 6), round(float(c[1]), 6))
        return c

    node_dict = {}
    for node in nodes:
        coords = coord_to_tuple(node.get("coords"))
        node_dict[coords] = node

    current_pos = coord_to_tuple(obs.get("robot_pos", np.array([0.0, 0.0])))
    # Find closest current node if exact match missing
    if current_pos not in node_dict:
        min_d = float('inf')
        closest = None
        for nc in node_dict:
            d = ((nc[0] - current_pos[0]) ** 2 + (nc[1] - current_pos[1]) ** 2) ** 0.5
            if d < min_d:
                min_d = d
                closest = nc
        if closest is not None:
            current_pos = closest

    if current_pos not in node_dict:
        return neighbors[0]

    # Build graph
    graph = {}
    utilities = {}
    visited_flags = {}
    for coord, node in node_dict.items():
        neighs = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = neighs
        utilities[coord] = float(node.get("utility", 0.0))
        visited_flags[coord] = bool(node.get("visited", False))

    def graph_distance(start, goal):
        if start == goal:
            return 0
        queue = deque([(start, 0)])
        seen = {start}
        while queue:
            curr, dist = queue.popleft()
            for neigh in graph.get(curr, []):
                if neigh not in seen:
                    if neigh == goal:
                        return dist + 1
                    seen.add(neigh)
                    queue.append((neigh, dist + 1))
        return float('inf')

    # Select best target by utility / (dist + 1)
    best_score = -1.0
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0.0 or visited_flags.get(tcoord, True):
            continue
        dist = graph_distance(current_pos, tcoord)
        if dist == float('inf') or dist == 0:
            continue
        score = util / (dist + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord

    if best_target is None:
        # fallback: max utility neighbor
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Find next node on shortest path to best_target
    def find_next_on_path(start, goal):
        if start == goal:
            return start
        queue = deque([start])
        parent = {start: None}
        while queue:
            curr = queue.popleft()
            if curr == goal:
                break
            for neigh in graph.get(curr, []):
                if neigh not in parent:
                    parent[neigh] = curr
                    queue.append(neigh)
        if goal not in parent:
            return None
        # Trace back to find the next after start
        curr = goal
        while parent.get(curr) != start and parent.get(curr) is not None:
            curr = parent[curr]
        return curr

    next_coord = find_next_on_path(current_pos, best_target)
    if next_coord is None or next_coord == current_pos:
        # fallback to local max utility
        best_utility = -1.0
        best_n = None
        for neigh_raw in neighbors:
            ncoord = coord_to_tuple(neigh_raw)
            util = utilities.get(ncoord, 0.0)
            if util > best_utility:
                best_utility = util
                best_n = neigh_raw
        return best_n if best_n is not None else neighbors[0]

    # Return the matching neighbor from obs["neighbors"]
    for neigh_raw in neighbors:
        if coord_to_tuple(neigh_raw) == next_coord:
            return neigh_raw
    return neighbors[0]

def run_evaluation(data_path, checkpoint, output_path):
    data_path = Path(data_path)
    model = load_model(checkpoint)
    output_path = Path(output_path)
    output_path.parent.mkdir(parents=True, exist_ok=True)

    eval_config_path = data_path / "eval_config.json"
    maps = []
    is_eval = eval_config_path.exists()
    if is_eval:
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        maps = config.get("maps", [])
    else:
        # local test on subset of training maps
        maps = []
        map_dir = data_path / "maps_train"
        for env_type in ["room", "tunnel", "outdoor"]:
            tdir = map_dir / env_type
            if tdir.exists():
                pngs = sorted(tdir.glob("*.png"))[:2]  # small for quick local test
                for p in pngs:
                    maps.append({"map_path": f"{env_type}/{p.name}", "env_type": env_type})
        print(f"Using {len(maps)} training maps for local testing.")

    results = []
    per_type_stats = {t: {"explored_rates": [], "travel_dists": [], "successes": []} for t in ["room", "tunnel", "outdoor"]}

    total_explored = 0.0
    total_success = 0
    success_dists = []
    for map_info in maps:
        if isinstance(map_info, dict):
            rel_path = map_info.get("map_path")
            env_type = map_info.get("env_type", "room")
        else:
            rel_path = str(map_info)
            env_type = rel_path.split("/")[0] if "/" in rel_path else "room"
        # determine map dir
        map_dir_name = "maps_eval" if (data_path / "maps_eval").exists() else "maps_train"
        full_map_path = str(data_path / map_dir_name / rel_path)

        env = ExplorationEnv(map_path=full_map_path)
        obs = env.reset()
        step_count = 0
        max_steps = 128
        done = False
        while not done and step_count < max_steps:
            target = select_waypoint(obs, model)
            if target is None or target not in obs.get("neighbors", []):
                break
            obs, info = env.step(target)
            done = info.get("done", False) or obs.get("done", False)
            step_count += 1
        metrics = env.get_metrics()
        explored_rate = float(metrics.get("explored_rate", 0.0))
        travel_distance = float(metrics.get("travel_distance", 0.0))
        success = 1 if explored_rate > 0.9999 else 0
        results.append({
            "map_path": rel_path,
            "env_type": env_type,
            "success": success,
            "travel_distance": travel_distance,
            "explored_rate": explored_rate
        })
        per_type_stats[env_type]["explored_rates"].append(explored_rate)
        per_type_stats[env_type]["travel_dists"].append(travel_distance if success else 0.0)
        per_type_stats[env_type]["successes"].append(success)
        total_explored += explored_rate
        if success:
            success_dists.append(travel_distance)
        total_success += success

    n_episodes = len(results)
    if n_episodes == 0:
        output = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0, "per_episode": [], "per_type": {}, "total_episodes": 0}
    else:
        explored_rate = total_explored / n_episodes
        success_rate = total_success / n_episodes
        travel_distance = sum(success_dists) / len(success_dists) if success_dists else 0.0

        per_type = {}
        for t in per_type_stats:
            stats = per_type_stats[t]
            n_t = len(stats["explored_rates"])
            if n_t > 0:
                er = sum(stats["explored_rates"]) / n_t
                sr = sum(stats["successes"]) / n_t
                sd = [d for d, s in zip(stats["travel_dists"], stats["successes"]) if s == 1]
                td = sum(sd) / len(sd) if sd else 0.0
                per_type[t] = {
                    "explored_rate": float(er),
                    "travel_distance": float(td),
                    "success_rate": float(sr)
                }
            else:
                per_type[t] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}

        output = {
            "explored_rate": float(explored_rate),
            "travel_distance": float(travel_distance),
            "success_rate": float(success_rate),
            "per_episode": results,
            "per_type": per_type,
            "total_episodes": n_episodes
        }

    with open(output_path, "w") as f:
        json.dump(output, f, indent=2)

    print("Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    if not is_eval:
        print("Local test on train subset done.")
    return output

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, required=True)
    parser.add_argument("--checkpoint", type=str, required=True)
    parser.add_argument("--output", type=str, required=True)
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
